const body = $input.first().json.body || $input.first().json;
const data = body.data || body;
const key = data.key || {};
const remoteJid = key.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net','').replace('@g.us','').replace(/[^0-9]/g,'');

if (!phone || key.fromMe === true || remoteJid.includes('@g.us')) return [];

const msg = data.message || {};
const message = msg.conversation || (msg.extendedTextMessage && msg.extendedTextMessage.text) || '';

// Detectar mensajes con imagen
const isImage = !!msg.imageMessage;
const isDocument = !!(msg.documentMessage || msg.documentWithCaptionMessage);
const imageCaption = isImage ? (msg.imageMessage.caption || '') : '';
const imageThumbnailBase64 = isImage && msg.imageMessage.jpegThumbnail
  ? msg.imageMessage.jpegThumbnail
  : null;

// Permitir texto, imágenes y documentos; ignorar mensajes vacíos sin media
if (!message.trim() && !imageCaption.trim() && !isImage && !isDocument) return [];

const messageType = isImage ? 'image' : (isDocument ? 'document' : 'text');
const effectiveMessage = message.trim() || imageCaption.trim() || (isImage ? '[imagen]' : '[documento]');

return [{
  json: {
    phone,
    message: effectiveMessage,
    messageType,
    imageThumbnailBase64,
    pushName: data.pushName || 'Cliente',
    instanceName: body.instance || '',
    messageId: key.id || '',
    timestamp: data.messageTimestamp || Date.now()
  }
}];

const msg = $('Normalizar Mensaje').first().json;
const messageType = msg.messageType || 'text';
const imageThumbnailBase64 = msg.imageThumbnailBase64 || null;
const api = $('Buscar Tenant Backend').first().json;
const bc = api.businessConfig || {};

// Verificar horario de atencion
const tz = bc.businessHours && bc.businessHours.timezone ? bc.businessHours.timezone : 'America/Bogota';
const now = new Date();
const localTime = new Intl.DateTimeFormat('es-CO', { timeZone: tz, hour: '2-digit', minute: '2-digit', hourCycle: 'h23' }).format(now);
const dayName = new Intl.DateTimeFormat('es-CO', { timeZone: tz, weekday: 'long' }).format(now);
const dayMap = { lunes: 'monday', martes: 'tuesday', miercoles: 'wednesday', jueves: 'thursday', viernes: 'friday', sabado: 'saturday', domingo: 'sunday' };
const todayKey = dayMap[dayName.toLowerCase()] || dayName.toLowerCase();
const schedule = bc.businessHours && bc.businessHours.schedule ? bc.businessHours.schedule : [];
const todayKeyEs = dayName.charAt(0).toUpperCase() + dayName.slice(1).toLowerCase();
const todaySchedule = schedule.find(function(d) {
  var dLow = (d.day || '').toLowerCase();
  return dLow === todayKey || dLow === todayKeyEs.toLowerCase() ||
    d.day === todayKeyEs || d.day === todayKey;
});
const parts = localTime.split(':');
const hh = parseInt(parts[0], 10);
const mm = parseInt(parts[1], 10);
const nowMins = hh * 60 + mm;
let inHours = true;
if (todaySchedule && todaySchedule.isOpen) {
  const op = (todaySchedule.open || '00:00').split(':');
  const cl = (todaySchedule.close || '23:59').split(':');
  const openMins = parseInt(op[0], 10) * 60 + parseInt(op[1], 10);
  const closeMins = parseInt(cl[0], 10) * 60 + parseInt(cl[1], 10);
  inHours = nowMins >= openMins && nowMins <= closeMins;
} else if (todaySchedule && !todaySchedule.isOpen) {
  inHours = false;
}

// Verificar credenciales Evolution API
if (!api.evolutionApiUrl || !api.evolutionApiKey) {
  throw new Error('[SharkByte] Tenant ' + api.tenantId + ' sin credenciales Evolution API configuradas.');
}

// Catalogo como texto plano
const catalogLines = (bc.catalog || []).map(function(p) {
  var line = '- ' + p.name;
  if (p.price) line += ' | $' + Number(p.price).toLocaleString('es-CO');
  if (p.category) line += ' | ' + p.category;
  if (p.available === false) line += ' [NO DISPONIBLE]';
  if (p.description) line += ': ' + p.description;
  return line;
});

const faqLines = (bc.faq || []).map(function(f) {
  return 'P: ' + f.question + '\nR: ' + f.answer;
});

// INSTRUCCION DE CLASIFICACION — va PRIMERO para maxima prioridad
var classificationInstruction =
  'INSTRUCCION CRITICA — DEBES SEGUIRLA OBLIGATORIAMENTE:\n' +
  'Al FINAL de tu respuesta al cliente, SIEMPRE agrega este bloque exacto:\n' +
  '<JSON>\n' +
  '{{"intent":"INTENT","confidence":SCORE,"suggested_response":"TU_RESPUESTA"}}\n' +
  '</JSON>\n\n' +
  'Donde INTENT es UNO de: ventas | soporte | agendamiento | informacion | humano | fallback\n' +
  'Donde SCORE es un numero entre 0.0 y 1.0 segun tu certeza\n' +
  'Donde TU_RESPUESTA es exactamente lo que acabas de responder al cliente\n\n' +
  'Clasificacion de intents:\n' +
  '- ventas: compra, precio, producto, catalogo, oferta, ordenar, disponibilidad, cuanto cuesta\n' +
  '- soporte: problema, fallo, error, queja, reclamo, no funciona, reparacion, garantia\n' +
  '- agendamiento: cita, reserva, agendar, turno, hora, calendario\n' +
  '- informacion: horario, direccion, contacto, como funciona, ubicacion\n' +
  '- humano: hablar con persona, agente humano, operador, representante\n' +
  '- fallback: saludo, despedida, mensaje ambiguo o sin categoria clara\n\n' +
  'IMPORTANTE: Primero responde al cliente normalmente, luego agrega el bloque <JSON>...</JSON>.\n' +
  'El bloque JSON debe estar en la ultima linea. NO lo omitas bajo ninguna circunstancia.\n\n';

var rawSystemMessage =
  classificationInstruction +
  '=== INSTRUCCIONES DEL NEGOCIO ===\n' +
  (bc.aiInstructions || 'Eres un asistente de atencion al cliente. Se amable y profesional.') +
  '\n\nNombre del negocio: ' + (bc.businessName || '') +
  '\nTono: ' + (bc.tone || 'amigable') +
  '\nIdioma: ' + (bc.language || 'es') +
  '\n\nCATALOGO DE PRODUCTOS:\n' + catalogLines.join('\n') +
  '\n\nPREGUNTAS FRECUENTES:\n' + faqLines.join('\n\n') +
  '\n\nMetodos de pago: ' + (bc.paymentMethods || []).join(', ') +
  '\nUbicacion: ' + (bc.location || '') +
  '\n\nAcciones permitidas: ' + (bc.allowedActions || []).join(', ') +
  '\nRestricciones: ' + (bc.restrictions || []).join(', ');

// Escapar { -> {{ y } -> }} para LangChain PromptTemplate
var openEscape = '{' + '{';
var closeEscape = '}' + '}';
var systemMessage = rawSystemMessage.split('{').join(openEscape).split('}').join(closeEscape);

return [{
  json: {
    phone: msg.phone,
    message: msg.message,
    pushName: msg.pushName,
    instanceName: msg.instanceName,
    messageId: msg.messageId,
    tenantId: api.tenantId,
    plan: api.plan,
    limits: api.limits,
    usage: api.usage,
    businessConfig: bc,
    aiInstructions: bc.aiInstructions || 'Eres un asistente de atencion al cliente.',
    businessName: bc.businessName || '',
    tone: bc.tone || 'amigable',
    language: bc.language || 'es',
    catalog: bc.catalog || [],
    faq: bc.faq || [],
    autoResponses: bc.autoResponses || {},
    automations: bc.automations || {},
    allowedActions: bc.allowedActions || [],
    restrictions: bc.restrictions || [],
    paymentMethods: bc.paymentMethods || [],
    location: bc.location || '',
    inHours: inHours,
    outOfHoursMessage: bc.outOfHoursMessage || 'Estamos fuera de horario. Te atenderemos pronto.',
    welcomeMessage: bc.welcomeMessage || '',
    evolutionApiUrl: api.evolutionApiUrl,
    tenantEmail: api.tenantEmail || '',
    messageType: messageType,
    imageThumbnailBase64: imageThumbnailBase64,
    evolutionApiKey: api.evolutionApiKey,
    systemMessage: systemMessage
  }
}];

const input = $input.first().json;
return [{ json: {
  memory: [],
  currentMessage: input.message || input.text || '',
  phone: input.phone || input.remoteJid || '',
  tenantId: input.tenantId || ''
} }];

const input = $input.first().json;
const aiOutput = input.output || input.text || '';
const config = $('Cargar Config Negocio').first().json;
const userMessage = (config.message || '').toLowerCase();

let parsed;
try {
  const tagMatch = aiOutput.match(/<JSON>([\s\S]*?)<\/JSON>/);
  if (tagMatch) {
    parsed = JSON.parse(tagMatch[1].trim());
  } else {
    const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
    parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : null;
  }
} catch(e) {
  parsed = null;
}

if (!parsed || !parsed.intent || parsed.intent === 'fallback') {
  let intent = 'fallback';
  let confidence = 0;

  // Ventas: incluye verbos de mostrar/ver productos + keywords de compra
  const ventasKw = /precio|costo|cu[aá]nto|comprar?|pedir|ordenar|cat[aá]logo|producto|stock|disponib|ofer|promo|descuento|valor|cuestan|venden|mu[eé]strame|mostrar|ens[eé][ñn]ame|quiero ver|quiero saber|tienes|tienen|hay|foto|imagen|modelo|talla|color|zapato|calzado|camisa|pantalon|vestido|ropa|accesorio/i;
  const soporteKw = /problema|fallo|error|ayuda|queja|reclamo|no funciona|da[ñn]o|reparar|garant[ií]a|soporte|defecto|roto/i;
  const agendaKw = /cita|reserva|agendar|turno|hora libre|disponibilidad.*(?:cita|horario|turno)|(?:cita|turno).*disponib|cu[aá]ndo pueden atender|calendario|appointment|sacar.*cita|pedir.*cita|apartar.*cita/i;
  const infoKw = /horario|direcci[oó]n|ubicaci[oó]n|contacto|tel[eé]fono|informaci[oó]n|c[oó]mo llegar|d[oó]nde est[aá]n/i;
  const humanoKw = /hablar con|agente|persona real|humano|operador|representante|vendedor/i;

  if (humanoKw.test(userMessage))      { intent = 'humano';       confidence = 0.92; }
  else if (agendaKw.test(userMessage)) { intent = 'agendamiento'; confidence = 0.88; }
  else if (soporteKw.test(userMessage)){ intent = 'soporte';      confidence = 0.88; }
  else if (ventasKw.test(userMessage)) { intent = 'ventas';       confidence = 0.88; }
  else if (infoKw.test(userMessage))   { intent = 'informacion';  confidence = 0.85; }
  // Si el clasificador generó una respuesta de producto, forzar ventas
  else if (aiOutput && config.catalog && config.catalog.length > 0) {
    const catalogNames = config.catalog.map(function(p){ return (p.name||'').toLowerCase(); });
    const matchesCatalog = catalogNames.some(function(name){ return name.length > 2 && aiOutput.toLowerCase().includes(name); });
    if (matchesCatalog) { intent = 'ventas'; confidence = 0.82; }
    else                { intent = 'fallback'; confidence = 0; }
  }
  else                                  { intent = 'fallback';     confidence = 0;    }

  parsed = { intent: intent, confidence: confidence, suggested_response: aiOutput };
}

return [{
  json: {
    phone: config.phone,
    tenantId: config.tenantId,
    instanceName: config.instanceName,
    pushName: config.pushName,
    message: config.message,
    businessName: config.businessName,
    businessType: config.businessType || '',
    aiInstructions: config.aiInstructions || '',
    catalog: config.catalog || [],
    faq: config.faq || [],
    paymentMethods: config.paymentMethods || [],
    location: config.location || '',
    tone: config.tone || 'amigable',
    language: config.language || 'es',
    allowedActions: config.allowedActions || [],
    restrictions: config.restrictions || [],
    businessHours: (config.businessConfig && config.businessConfig.businessHours) || {},
    intent: parsed.intent || 'fallback',
    confidence: parseFloat(parsed.confidence) || 0,
    ai_response: parsed.suggested_response || aiOutput,
    classification_raw: aiOutput,
    tenantEmail: config.tenantEmail || '',
    messageType: config.messageType || 'text',
    imageThumbnailBase64: config.imageThumbnailBase64 || null,
    evolutionApiUrl: config.evolutionApiUrl || '',
    evolutionApiKey: config.evolutionApiKey || '',
    humanAgents: (config.businessConfig && config.businessConfig.humanAgents) || [],
    businessConfig: config.businessConfig || {}
  }
}];

const input = $input.first().json;
const config = $('Cargar Config Negocio').first().json;
const subResponse = input.response || input.ai_response || 'Lo siento, no pude procesar tu mensaje. Un agente te atenderá pronto.';

// Estimar tokens: ~4 chars por token (heurística básica)
const estimatedTokens = Math.ceil(
  ((config.message || '').length + subResponse.length) / 4
);

return [{
  json: {
    phone: config.phone,
    tenantId: config.tenantId,
    instanceName: config.instanceName,
    evolutionApiUrl: config.evolutionApiUrl,
    evolutionApiKey: config.evolutionApiKey,
    response_text: subResponse,
    intent: input.intent || 'unknown',
    confidence: input.confidence || 0,
    tokensUsed: estimatedTokens,
    timestamp: Date.now()
  }
}];

const config = $('Cargar Config Negocio').first().json;
const message = (config.message || '').toLowerCase().trim();
const rulesData = $input.first().json;
const rules = rulesData.rules || [];

// Clasificación de intención (si ya viene en el contexto del segundo paso)
const intentFromAI = config.intentFromAI || null;

let matchedRule = null;

for (const rule of rules) {
  if (!rule.isActive) continue;

  if (rule.trigger.type === 'keyword') {
    const keywords = (rule.trigger.keywords || []).map(k => k.toLowerCase());
    const matchMode = rule.trigger.matchMode || 'any';
    const matched = matchMode === 'any'
      ? keywords.some(kw => message.includes(kw))
      : keywords.every(kw => message.includes(kw));
    if (matched) { matchedRule = rule; break; }
  }

  // Reglas de intent: se evalúan solo si viene el intent del clasificador
  if (rule.trigger.type === 'intent' && intentFromAI) {
    if (rule.trigger.intent === intentFromAI) {
      matchedRule = rule;
      break;
    }
  }
}

return [{
  json: {
    ...config,
    ruleMatched: matchedRule !== null,
    ruleName: matchedRule ? matchedRule.name : null,
    actionType: matchedRule ? matchedRule.action.type : null,
    replyMessage: matchedRule ? matchedRule.action.replyMessage : null,
    notifyEmail: matchedRule ? matchedRule.action.notifyEmail : null,
    ruleTag: matchedRule ? matchedRule.action.tag : null,
    ruleId: matchedRule ? matchedRule._id : null
  }
}];

const data = $input.first().json;
const action = data.actionType;
let response_text = '';
if (action === 'auto_reply') {
  response_text = data.replyMessage || 'Estamos procesando tu solicitud.';
} else if (action === 'notify_admin') {
  response_text = data.replyMessage || 'Tu mensaje fue registrado. Un agente te contactara pronto.';
} else if (action === 'escalate') {
  response_text = 'Tu solicitud fue escalada a un supervisor. Te contactaremos a la brevedad.';
} else if (action === 'tag') {
  response_text = 'Hemos marcado tu mensaje como prioritario. Un agente especializado te atendera enseguida.';
} else if (action === 'webhook') {
  response_text = 'Tu solicitud esta siendo procesada.';
} else {
  response_text = 'Recibimos tu mensaje. En breve te atendemos.';
}
return [{
  json: {
    phone: data.phone,
    tenantId: data.tenantId,
    instanceName: data.instanceName,
    response_text,
    intent: 'automation_rule',
    confidence: 1.0,
    ruleId: data.ruleId,
    ruleName: data.ruleName,
    actionType: action,
    timestamp: Date.now()
  }
}];

// Este nodo se activa cuando un sub-workflow (Ventas, Soporte, etc.) falla
// Genera una respuesta de fallback amigable para el cliente
const config = $('Cargar Config Negocio').first().json;
const pushName = config.pushName || 'cliente';
const businessName = config.businessName || 'nuestro equipo';

// Error proveniente del executeWorkflow
const errorInfo = $input.first().json || {};
const errorMsg = errorInfo.error?.message || 'Error desconocido en sub-workflow';
console.error('[Router] Error en sub-workflow:', errorMsg, '| tenantId:', config.tenantId);

// Respuesta amigable para el usuario
const response = `Hola ${pushName}, en este momento estamos teniendo un inconveniente técnico. Un agente de ${businessName} te contactará en breve para asistirte. Disculpa las molestias.`;

return [{
  json: {
    response,
    intent: 'error',
    confidence: 0,
    error: true,
    errorMessage: errorMsg
  }
}];
